export type BarChartValueConfig<T> = {
    key: keyof T;
    color: string;
    opacity?: number;
};
export type BarChartConfig<T> = {
    values: BarChartValueConfig<T>[];
    height?: string;
};
export declare function createRowBarChartStyle<T>(row: T, tableData: T[], config: BarChartConfig<T>): {
    style: string;
};
